const body = $input.item.json;
const from = body.from || body.From || '';
const text = (body.text?.body || body.Body || '').toLowerCase().trim();
return [{ json: { from, text, text_original: text, to: body.to || body.To || '', timestamp: body.timestamp || Date.now(), session_key: 'session_' + from } }];

const negociosDB = { '5532652927': { id: 1, nombre: 'Body Trainer Gym Arboledas', tipo: 'gimnasio', telefono: '5532652927', direccion: 'Calzada de los Jinetes 35, Las Arboledas', horarios: 'Lun-Vie 5AM-11PM | Sab-Dom 7AM-7PM | 365 dias', slug: 'body-trainer-arboledas', servicios: [ { id: 1, nombre: 'Visita del dia', precio: 50, emoji: '1' }, { id: 2, nombre: 'Semana', precio: 199, emoji: '2' }, { id: 3, nombre: 'Mensual ilimitado', precio: 699, destacado: true, emoji: '3' }, { id: 4, nombre: 'Estudiante mensual', precio: 599, emoji: '4' } ] } };
const to = $input.item.json.to || '5532652927';
const negocio = negociosDB[to] || negociosDB['5532652927'];
const session = { step: 'inicio', data: {} };
return [{ json: { ...$input.item.json, negocio, session } }];

const { negocio, text } = $input.item.json;
const tipoMsg = { gimnasio: 'Quieres ver nuestros planes y precios?', barberia: 'Quieres agendar una cita?', restaurante: 'Quieres hacer un pedido o reservar mesa?', cafe: 'Quieres hacer un pedido?' };
const mensaje = 'Hola! Soy el asistente de ' + negocio.nombre + '. ' + (tipoMsg[negocio.tipo] || '') + '

1. Ver servicios/planes
2. Agendar/Reservar
3. Horarios y ubicacion
4. Hablar con el equipo';
return [{ json: { ...$input.item.json, mensaje_respuesta: mensaje, nuevo_step: 'seleccion_accion' } }];

const event = $input.item.json;
if (event.type === 'checkout.session.completed') {
  const session = event.data?.object || {};
  return [{ json: { pago_ok: true, stripe_id: session.id, amount: (session.amount_total||0)/100, usuario: session.customer_details?.name, telefono: session.customer_details?.phone } }];
}
return [{ json: { skip: true, event_type: event.type } }];
